(() => {
  const fields = $('Pegar informação da ficha').item.json.data.card.fields || [];
  const f = fields.find(x => (x.field?.id || x.indexName || "") === "cliente");
  const arr = Array.isArray(f?.array_value)
    ? f.array_value
    : f?.value != null
      ? [f.value]
      : [];
  return arr
    .map(v => (typeof v === "string" ? v.trim() : String(v)))
    .filter(Boolean)
    .join(", "); // single unquoted string
})()
}}

